patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 703065280096..3475574a0079 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3071,6 +3071,33 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
   if (Value *V = foldAndOrOfICmpsOfAndWithPow2(LHS, RHS, &I, IsAnd, IsLogical))
     return V;

+  // (icmp ult (add A, B), A) | (icmp ult (add A, B), B) -> (icmp ult (add A, B), A)
+  // (icmp uge (add A, B), A) & (icmp uge (add A, B), B) -> (icmp uge (add A, B), A)
+  // Both icmp check for (un)signed overflow of A + B, so they're equivalent.
+  if (!IsLogical && LHS->getPredicate() == RHS->getPredicate()) {
+    ICmpInst::Predicate Pred = LHS->getPredicate();
+    Value *LHS0 = LHS->getOperand(0), *LHS1 = LHS->getOperand(1);
+    Value *RHS0 = RHS->getOperand(0), *RHS1 = RHS->getOperand(1);
+    if ((IsAnd && Pred == ICmpInst::ICMP_UGE) ||
+        (!IsAnd && Pred == ICmpInst::ICMP_ULT)) {
+      // Check if both compare the same add against one of its operands
+      if (LHS0 == RHS0 && LHS0->getType()->isIntegerTy()) {
+        if (auto *Add = dyn_cast<BinaryOperator>(LHS0)) {
+          if (Add->getOpcode() == Instruction::Add) {
+            Value *AddOp0 = Add->getOperand(0);
+            Value *AddOp1 = Add->getOperand(1);
+            if (((LHS1 == AddOp0 || LHS1 == AddOp1) &&
+                 (RHS1 == AddOp0 || RHS1 == AddOp1) &&
+                 LHS1 != RHS1)) {
+              return LHS;
+            }
+          }
+        }
+      }
+    }
+  }
+
+
   ICmpInst::Predicate PredL = LHS->getPredicate(), PredR = RHS->getPredicate();
   Value *LHS0 = LHS->getOperand(0), *RHS0 = RHS->getOperand(0);
   Value *LHS1 = LHS->getOperand(1), *RHS1 = RHS->getOperand(1);

